// Read HTML + read callback/analysis DIRECTLY from Webhook (bulletproof)
const raw = $input.first().json;
let html = '';
if (typeof raw.data === 'string') html = raw.data;
else if (typeof raw.body === 'string') html = raw.body;
else if (typeof raw === 'string') html = raw;
else html = JSON.stringify(raw);

const keyword = $node.Webhook.json.body.keyword || '';
const analysis_id = $node.Webhook.json.body.analysis_id || '';
const callback_url = $node.Webhook.json.body.callback_url || '';

// Extract organic results
const results = [];
const linkRegex = /<a[^>]+href="(https?:\/\/[^"]+)"[^>]*>[\s\S]*?<h3[^>]*>([\s\S]*?)<\/h3>/gi;
let match;
while ((match = linkRegex.exec(html)) !== null && results.length < 10) {
  const url = match[1];
  const title = match[2].replace(/<[^>]+>/g, '').trim();
  if (!url.includes('google.') && !url.includes('gstatic.') && url.startsWith('http')) {
    try { results.push({position: results.length+1, url, title, domain: new URL(url).hostname}); } catch(e) {}
  }
}
if (results.length === 0) {
  const alt = /href="(https?:\/\/(?!www\.google|gstatic|accounts\.google)[^"]{15,})"/gi;
  while ((match = alt.exec(html)) !== null && results.length < 10) {
    try { const url = match[1]; const d = new URL(url).hostname; if (!results.some(r=>r.domain===d)) results.push({position: results.length+1, url, title: d, domain: d}); } catch(e) {}
  }
}

// PAA questions
const questions = [];
const paa = /data-q="([^"]+)"/g;
while ((match = paa.exec(html)) !== null && questions.length < 10) questions.push(match[1]);

return [{json: {analysis_id, callback_url, keyword, results, questions}}];

// Build final payload — read callback DIRECTLY from Webhook node (never undefined)
const parsed = $input.first().json;
const results = parsed.results || [];

const competitors = results.map(r => ({
  position: r.position, url: r.url, domain: r.domain, title: r.title,
  word_count: 0, h1_count: 0, h2_count: 0, h3_count: 0, images: 0, schema_types: '', top_keywords: [], headings: {h1:[],h2:[],h3:[]}
}));

return [{json: {
  analysis_id: $node.Webhook.json.body.analysis_id || '',
  callback_url: $node.Webhook.json.body.callback_url || '',
  avg_word_count: 0,
  avg_headings: 0,
  lsi_keywords: [],
  content_gap: [],
  questions: parsed.questions || [],
  competitors: competitors
}}];
